6	//! Static shared-memory access through `llvm.addressof` (guards issue #54).
7	//!
8	//! The kernel does `OUTPUT_NORM[0] = OUTPUT_NORM[0] * weight` on a static
9	//! `SharedArray<f32, 1>`. Before the fix in PR #55, the llvm-export textual exporter
10	//! gave the `addressof @__shared_mem_N` result a `%vN` SSA name even though
11	//! `addressof` is virtual in textual LLVM IR (it has no instruction form,
12	//! only a symbol reference at use sites). When the use printed before the
13	//! addressof's block, the GEP referenced a `%vN` no instruction defined and
14	//! libNVVM rejected the IR.
15	//!
16	//! This example launches the kernel through `cuda_host::ltoir::load_kernel_module`,
17	//! which compiles the cuda-oxide-emitted NVVM IR via libNVVM and links the
18	//! cubin via nvJitLink. A dangling SSA reference in the `.ll` would fail at
19	//! libNVVM's verifier before the kernel could run, so a regression of #54
20	//! is now a hard runtime failure instead of a silent build artifact.
21	//!
22	//! Run: `cargo oxide run addressof_sharedarray`
23	
24	#![allow(static_mut_refs)]
25	#![allow(clippy::assign_op_pattern)] // Expanded assignment preserves the addressof repro CFG.
26	
27	use cuda_core::{CudaContext, DeviceBuffer, LaunchConfig};
28	use cuda_device::{DisjointSlice, SharedArray, device, kernel, thread};
29	use cuda_host::{cuda_module, ltoir};
30	
31	#[cuda_module]
32	mod kernels {
33	    use super::*;
34	
35	    #[kernel]
36	    pub fn sharedarray_late_use(seed: f32, mut out: DisjointSlice<f32>) {
37	        static mut OUTPUT_NORM: SharedArray<f32, 1> = SharedArray::UNINIT;
38	
39	        if thread::index_1d().get() == 0 {
40	            unsafe {
41	                OUTPUT_NORM[0] = seed;
42	                let weight = repro_weight();
43	                // Issue #54 repro shape: load addressof[0], multiply, store.
44	                OUTPUT_NORM[0] = OUTPUT_NORM[0] * weight;
45	                *out.get_unchecked_mut(0) = OUTPUT_NORM[0];
46	            }
47	        }
48	    }
49	
50	    #[inline(never)]
51	    #[device]
52	    fn repro_weight() -> f32 {
53	        3.0
54	    }
55	}
56	
57	fn main() -> Result<(), Box<dyn std::error::Error>> {
58	    println!("=== addressof_sharedarray (issue #54 regression) ===");
59	
60	    let ctx = CudaContext::new(0)?;
61	    let stream = ctx.default_stream();
62	
63	    // Forces the cuda-oxide-emitted `.ll` through libNVVM + nvJitLink.
64	    // A dangling SSA reference in the IR would fail libNVVM's verifier here.
65	    let raw_module = ltoir::load_kernel_module(&ctx, "addressof_sharedarray")?;
66	    let module = kernels::from_module(raw_module).expect("typed module init failed");
67	
68	    let cfg = LaunchConfig::for_num_elems(1);
69	    let mut out = DeviceBuffer::<f32>::zeroed(&stream, 1)?;
70	    let seed: f32 = 7.0;
71	
72	    // SAFETY: one thread is launched, matching the kernel's single-element
73	    // output access and fixed shared-memory use.
74	    unsafe { module.sharedarray_late_use(stream.as_ref(), cfg, seed, &mut out) }?;
75	
76	    let result = out.to_host_vec(&stream)?[0];
77	    let expected: f32 = 21.0; // seed * repro_weight() == 7.0 * 3.0
78	
79	    if (result - expected).abs() < f32::EPSILON {
80	        println!("PASS addressof_sharedarray: seed={seed}, result={result}");
81	        Ok(())
82	    } else {
83	        eprintln!("FAIL addressof_sharedarray: got {result}, expected {expected}");
84	        std::process::exit(1);
85	    }
86	}
